import{c as t,Q as a,j as o,m as d}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/configuration.md","filePath":"guide/configuration.md"}'),n={name:"guide/configuration.md"};function i(r,e,c,s,l,g){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>Open VS Code settings (<code>Cmd+,</code>) and search for &quot;l33t-speak&quot;.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>l33t-speak.preferredEngine</code></td><td><code>auto</code></td><td>Speech engine: <code>auto</code>, <code>macos</code>, <code>windows</code>, or <code>webview</code></td></tr><tr><td><code>l33t-speak.microphone</code></td><td><code>null</code></td><td>Device ID of preferred microphone</td></tr><tr><td><code>l33t-speak.language</code></td><td><code>en-US</code></td><td>BCP-47 language code (e.g., <code>en-GB</code>, <code>fr-FR</code>, <code>de-DE</code>)</td></tr><tr><td><code>l33t-speak.insertMode</code></td><td><code>final</code></td><td><code>final</code> inserts after you stop; <code>streaming</code> inserts as you speak</td></tr><tr><td><code>l33t-speak.enableGateway</code></td><td><code>false</code></td><td>Send dictation to the l33t gateway for AI processing</td></tr><tr><td><code>l33t-speak.gatewayUrl</code></td><td><code>https://gateway.l33tspeak.dev</code></td><td>Base URL of the gateway API</td></tr><tr><td><code>l33t-speak.gatewayApiKey</code></td><td><code>&quot;&quot;</code></td><td>Placeholder — use <code>Cmd+Shift+P</code> → &quot;Set Gateway API Key&quot; to store in OS keychain</td></tr></tbody></table><h2 id="gateway-settings" tabindex="-1">Gateway Settings <a class="header-anchor" href="#gateway-settings" aria-label="Permalink to &quot;Gateway Settings&quot;">​</a></h2><p>When the gateway is configured (see <a href="/guide/gateway.html">Gateway Setup</a>), three additional settings control how dictation is processed:</p><h3 id="l33t-speak-enablegateway" tabindex="-1"><code>l33t-speak.enableGateway</code> <a class="header-anchor" href="#l33t-speak-enablegateway" aria-label="Permalink to &quot;`l33t-speak.enableGateway`&quot;">​</a></h3><p>Toggles gateway AI processing on/off. <strong>This is auto-enabled when you set an API key</strong> — no manual toggle needed. Turn it off to disable gateway processing without clearing your key.</p><h3 id="l33t-speak-gatewayurl" tabindex="-1"><code>l33t-speak.gatewayUrl</code> <a class="header-anchor" href="#l33t-speak-gatewayurl" aria-label="Permalink to &quot;`l33t-speak.gatewayUrl`&quot;">​</a></h3><p>The URL of your gateway API. Default is <code>https://gateway.l33tspeak.dev</code> for the hosted gateway. Use <code>http://localhost:3000</code> for local Docker development.</p><h3 id="l33t-speak-gatewayapikey" tabindex="-1"><code>l33t-speak.gatewayApiKey</code> <a class="header-anchor" href="#l33t-speak-gatewayapikey" aria-label="Permalink to &quot;`l33t-speak.gatewayApiKey`&quot;">​</a></h3><p>Placeholder text only. The actual API key is stored securely in your operating system&#39;s keychain via VS Code&#39;s <a href="https://code.visualstudio.com/api/references/vscode-api#SecretStorage" target="_blank" rel="noreferrer">SecretStorage API</a>. Use the command <strong>&quot;L33t Speak: Set Gateway API Key&quot;</strong> to enter your key — it will never appear in your settings file.</p><h2 id="engine-selection" tabindex="-1">Engine Selection <a class="header-anchor" href="#engine-selection" aria-label="Permalink to &quot;Engine Selection&quot;">​</a></h2><p>By default (<code>auto</code>), the extension picks the best available engine:</p><ul><li><strong>macOS</strong> → native SFSpeechRecognizer (offline, fast)</li><li><strong>Windows</strong> → native System.Speech (offline)</li><li><strong>Other</strong> → WebView with Web Speech API (requires internet)</li></ul><p>Override with <code>l33t-speak.preferredEngine</code> if you want to force a specific engine.</p><h2 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h2><p>Set <code>l33t-speak.language</code> to any BCP-47 locale supported by your platform&#39;s speech recognizer. Common values:</p><ul><li><code>en-US</code> — English (US)</li><li><code>en-GB</code> — English (UK)</li><li><code>fr-FR</code> — French</li><li><code>de-DE</code> — German</li><li><code>es-ES</code> — Spanish</li><li><code>ja-JP</code> — Japanese</li></ul>',19)])])}const u=t(n,[["render",i]]);export{p as __pageData,u as default};
